// Verify /api/directions returns 400 for out-of-range coordinates
async function testDirectionsOutOfRange() {
  const res = await fetch('http://localhost:3001/api/directions?lat=45&lon=200');
  assertEquals(res.status, 400);
  const body = await res.json();
  assertEquals(body.error, true);
  assertEquals(body.message, 'Invalid coordinates: lat must be -90..90, lon must be -180..180');
}
